ValidationRule.errorConditionFormula:
AND(
  NOT( $Permission.C_PERM_8030_Bypass_OwnedByCompany_V_RULE )
 ,ISCHANGED(OwnerId)
 ,LEFT(OwnerId,3)='00G'
 ,CONTAINS('AES,LSDX', TEXT(Owned_by_Company__c))

 /*If PKIQ exists, then PKIQ.OBC ELSE Owner.Queue.OBC*/
 ,IF(PKI_Queue__c !=null
     ,TEXT(PKI_Queue__r.Owned_By_Company__c) != TEXT(Owned_by_Company__c)
     /*,NOT(CONTAINS( Owner:Queue.QueueName, TEXT(Owned_by_Company__c)))*/
     /*Source Ticket - INC0394238,INC0395835*/
     ,False
    )
  )
